insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (1,'recipe-1','씻은 김치 맑은 돼지찌개','김치찌개','soup',ARRAY['저나트륨','저칼륨']::text[],'나트륨과 칼륨이 높은 김치 양념을 물에 완벽히 씻어내고, 고춧가루로 칼칼함을 내어 나트륨을 극도로 줄입니다.',ARRAY['씻은 배추김치 30g','돼지고기 30g','양파 10g','대파 5g','다진 마늘 2g','고춧가루 3g','물 200g']::text[],'{"kcal": 150.0, "protein": 10.0, "sodium": 210.0, "potassium": 150.0, "phosphorus": 60.0}'::jsonb,ARRAY['배추김치는 물에 여러 번 헹궈 고춧가루와 짠맛을 완벽히 씻어내고 잘게 썹니다.','양파와 대파는 채 썰어 미지근한 물에 2시간 담가 칼륨을 뺍니다.','냄비에 기름을 살짝 두르고 돼지고기와 씻은 김치를 달달 볶아 풍미를 냅니다.','물을 붓고 끓이다가 전처리한 채소와 고춧가루, 다진 마늘을 넣어 간 없이 얼큰하게 끓여냅니다.']::text[],'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (2,'recipe-2','무염 맑은 얼갈이 된장국','된장찌개','soup',ARRAY['저칼륨','저나트륨']::text[],'고칼륨인 호박이나 감자를 철저히 배제하고, 데쳐서 칼륨을 뺀 얼갈이배추에 최소량의 저염된장만 사용합니다.',ARRAY['얼갈이배추 40g','저염된장 5g','다진 마늘 2g','물 200g','건새우 3g']::text[],'{"kcal": 35.0, "protein": 3.0, "sodium": 180.0, "potassium": 110.0, "phosphorus": 45.0}'::jsonb,ARRAY['얼갈이배추를 끓는 물에 푹 데친 후 찬물에 헹구고 물기를 꼭 짜서 칼륨을 1차로 버립니다.','냄비에 마른 건새우를 살짝 볶다가 물을 붓고 끓여 고소한 육수를 냅니다.','육수 건더기를 거른 후 저염된장을 아주 연하게 풉니다.','전처리한 얼갈이와 마늘을 넣고 한소끔 끓여냅니다.']::text[],'https://images.unsplash.com/photo-1547592180-85f173990554?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (3,'recipe-3','가쓰오부시 맑은 미역국','미역국','soup',ARRAY['저나트륨']::text[],'고염분 소금이나 국간장 대신 가쓰오부시 육수를 진하게 우려내어 감칠맛으로 대체합니다.',ARRAY['건미역 5g','가쓰오부시 2g','양파 10g','미향 1g','물 300g']::text[],'{"kcal": 20.0, "protein": 1.0, "sodium": 190.0, "potassium": 80.0, "phosphorus": 20.0}'::jsonb,ARRAY['건미역은 찬물에 충분히 불린 후 바락바락 씻어 염분을 빼고 물기를 짭니다.','양파는 채 썰어 2시간 이상 물에 담가 칼륨을 제거합니다.','냄비에 물을 끓이고 가쓰오부시를 넣어 진하게 육수를 우려낸 후 건더기를 거릅니다.','육수에 미역과 전처리한 양파를 넣고 한소끔 끓인 뒤 미향으로 마무리합니다.']::text[],'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (4,'recipe-4','맑은 소고기 뭇국','소고기무국','soup',ARRAY['저나트륨','저칼륨']::text[],'시판 조미료 대신 수제 저염간장을 소량 사용하고 무는 데쳐서 칼륨을 완전히 뺍니다.',ARRAY['소고기 20g','무 20g','느타리버섯 10g','숙주 10g','저염간장 5g','물 200g']::text[],'{"kcal": 70.0, "protein": 7.0, "sodium": 220.0, "potassium": 140.0, "phosphorus": 60.0}'::jsonb,ARRAY['무와 숙주는 각각 끓는 물에 데쳐내어 고칼륨이 빠져나간 물을 버립니다.','냄비에 참기름을 살짝 두르고 소고기와 전처리한 무를 볶습니다.','고기가 익으면 물을 붓고 끓이다가 느타리버섯을 넣습니다.','데친 숙주와 저염간장을 풀어 개운하게 끓여냅니다.']::text[],'https://images.unsplash.com/photo-1547592180-85f173990554?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (5,'recipe-5','무염 맑은 닭곰탕','설렁탕/곰탕','soup',ARRAY['저나트륨','저인']::text[],'시판 스톡이나 화학조미료(고인산) 대신 닭뼈를 직접 우려낸 육수로 감칠맛을 완벽히 대체합니다.',ARRAY['닭가슴살 50g','닭뼈 100g','무 30g','대파 10g','마늘 5g','후추 0.1g','물 400g']::text[],'{"kcal": 85.0, "protein": 16.0, "sodium": 90.0, "potassium": 190.0, "phosphorus": 120.0}'::jsonb,ARRAY['닭뼈를 깨끗이 씻어 물, 마늘, 대파와 함께 푹 끓여 깊은 육수를 만듭니다.','육수가 끓을 때 닭가슴살을 넣어 익힌 후 건져내어 결대로 찢습니다.','무는 얇게 썰어 끓는 물에 데친 뒤 그 물을 버려 칼륨을 제거합니다.','맑게 거른 뜨거운 육수에 전처리한 무와 찢은 닭가슴살을 담고 후추로만 간을 합니다.']::text[],'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (6,'recipe-6','얼큰 황태 콩나물 수제비','수제비','soup',ARRAY['저나트륨','저칼륨']::text[],'조미료 대신 구운 황태머리 육수를 쓰고 수제비 반죽은 따로 삶아 염분과 칼륨을 1차 배출합니다.',ARRAY['콩나물 30g','황태머리 15g','밀가루 50g','고춧가루 5g','다진 마늘 2g','물 300g']::text[],'{"kcal": 220.0, "protein": 8.0, "sodium": 280.0, "potassium": 160.0, "phosphorus": 70.0}'::jsonb,ARRAY['밀가루 반죽을 만들어 끓는 물에 따로 데쳐내어 건져둡니다.','콩나물은 끓는 물에 데쳐내어 칼륨이 빠진 물을 버립니다.','황태머리를 불에 굽고 찬물에 끓여 시원한 육수를 거릅니다.','육수에 고춧가루를 풀고 따로 데친 수제비와 콩나물, 마늘을 넣어 얼큰하게 끓여냅니다.']::text[],'https://images.unsplash.com/photo-1547592180-85f173990554?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (7,'recipe-7','얼큰 닭개장','육개장','soup',ARRAY['저칼륨','저나트륨']::text[],'고칼륨인 토란대 대신 전처리한 무와 찢은 닭가슴살을 고춧가루로 맵게 끓여 짠맛을 덮습니다.',ARRAY['닭가슴살 40g','무 30g','대파 10g','숙주 10g','고춧가루 5g','마늘 3g','참기름 2g','물 300g']::text[],'{"kcal": 110.0, "protein": 12.0, "sodium": 150.0, "potassium": 180.0, "phosphorus": 90.0}'::jsonb,ARRAY['무와 대파, 숙주는 각각 끓는 물에 데쳐 칼륨을 뺍니다.','삶아낸 닭가슴살을 잘게 찢어 다진 마늘, 고춧가루, 참기름에 버무립니다.','냄비에 양념한 닭고기와 전처리한 채소를 넣고 볶습니다.','물을 부어 푹 끓여내 얼큰한 국물을 완성합니다.']::text[],'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (8,'recipe-8','코다리 맑은 들깨탕','생선찌개','soup',ARRAY['저인','저나트륨']::text[],'인이 많은 가공 어묵 피하고 코다리를 쓰며, 소금 대신 다시마 육수와 들깨가루로 고소함을 더합니다.',ARRAY['코다리 100g','무 40g','양파 10g','들깨가루 10g','다시마 2g','물 300g']::text[],'{"kcal": 110.0, "protein": 18.0, "sodium": 150.0, "potassium": 210.0, "phosphorus": 130.0}'::jsonb,ARRAY['무와 양파는 얇게 썰어 따뜻한 물에 2시간 담가 칼륨을 제거합니다.','코다리는 씻어서 다진 마늘과 후추로 밑간을 해둡니다.','다시마를 연하게 끓인 육수에 전처리한 무를 넣고 익힙니다.','무가 익으면 코다리를 넣고 익히다가 들깨가루를 듬뿍 풀어 완성합니다.']::text[],'https://images.unsplash.com/photo-1547592180-85f173990554?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (9,'recipe-9','맑은 바지락 순두부 백탕','순두부찌개','soup',ARRAY['저칼륨','저나트륨']::text[],'나트륨이 높은 고추장 양념을 빼고 맑은 백탕으로 끓여 청양고추의 칼칼함으로 맛을 냅니다.',ARRAY['순두부 100g','바지락 30g','마늘 5g','청양고추 3g','물 200g']::text[],'{"kcal": 80.0, "protein": 10.0, "sodium": 160.0, "potassium": 140.0, "phosphorus": 80.0}'::jsonb,ARRAY['바지락은 해감하고, 마늘은 편으로 썰고 청양고추는 송송 썹니다.','끓는 물에 바지락과 마늘을 넣고 끓이며 거품을 걷어냅니다.','바지락이 입을 벌리면 순두부를 넣고 한소끔 더 끓입니다.','마지막에 청양고추를 넣어 소금 없이 칼칼하게 마무리합니다.']::text[],'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (10,'recipe-10','소고기 들깨 무탕','갈비탕','soup',ARRAY['저나트륨','저칼륨']::text[],'고칼륨 토란이나 고구마 대신 전처리한 무를 넣고 들깨가루로 고소함을 극대화하여 나트륨을 배제합니다.',ARRAY['소고기(양지) 30g','무 40g','느타리버섯 10g','들깨가루 15g','물 250g']::text[],'{"kcal": 160.0, "protein": 9.0, "sodium": 110.0, "potassium": 180.0, "phosphorus": 90.0}'::jsonb,ARRAY['양지를 끓여 육수를 낸 후 고기는 건져 찢어둡니다.','무는 끓는 물에 푹 데친 후 그 물을 완전히 버립니다.','고기 육수에 전처리한 무와 버섯, 찢어둔 고기를 넣고 끓입니다.','채소가 익으면 들깨가루를 듬뿍 풀어 소금 없이 고소하게 마무리합니다.']::text[],'https://images.unsplash.com/photo-1547592180-85f173990554?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (11,'recipe-11','송이버섯 닭고기 잡채','잡채','main',ARRAY['저칼륨','저인']::text[],'고칼륨인 목이버섯 대신 고급스러운 향을 내는 송이버섯을 쓰고, 고인산 가공육 대신 닭가슴살을 씁니다. 당면은 칼륨과 인이 매우 낮아 안전합니다.',ARRAY['당면 50g','닭가슴살 30g','송이버섯 20g','양파 10g','당근 10g','저염간장 5g','참기름 2g','마늘 2g']::text[],'{"kcal": 210.0, "protein": 9.0, "sodium": 130.0, "potassium": 110.0, "phosphorus": 50.0}'::jsonb,ARRAY['당근과 양파는 가늘게 채 썰어 따뜻한 물에 2시간 이상 담가 칼륨을 완벽히 뺍니다.','끓는 물에 당면을 부드럽게 삶아 건져 물기를 뺍니다.','팬에 기름을 두르고 다진 마늘, 닭고기, 얇게 썬 송이버섯을 먼저 볶아 향을 냅니다.','전처리한 채소와 삶은 당면을 넣고, 저염간장과 참기름으로 볶아 완성합니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (12,'recipe-12','사과즙 간장불고기','불고기','main',ARRAY['저나트륨']::text[],'짠 간장 양념의 양을 극도로 줄이고, 사과즙을 갈아 넣어 천연 단맛과 부드러운 향으로 짠맛의 빈자리를 채웁니다.',ARRAY['소고기 50g','양파 15g','대파 5g','사과 20g','마늘 2g','저염간장 3g','참기름 2g']::text[],'{"kcal": 150.0, "protein": 10.0, "sodium": 160.0, "potassium": 190.0, "phosphorus": 70.0}'::jsonb,ARRAY['양파와 대파는 물에 담가 칼륨을 뺀 후 썹니다. 사과는 강판에 갈아 즙을 냅니다.','소고기에 사과즙, 마늘, 저염간장을 넣고 버무려 30분 재웁니다.','기름 두른 팬에 양념된 고기를 볶습니다.','고기가 익어갈 때 전처리한 채소와 참기름을 넣고 빠르게 볶아냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (13,'recipe-13','파인애플 돼지볶음','제육볶음','main',ARRAY['저나트륨']::text[],'고추장 대신 파인애플을 갈아 넣어 연육 작용과 강한 단맛을 유도, 고춧가루만으로 간장/소금을 대체합니다.',ARRAY['돼지고기 50g','파인애플 30g','양배추 15g','양파 10g','고춧가루 3g','다진 마늘 2g']::text[],'{"kcal": 160.0, "protein": 10.0, "sodium": 50.0, "potassium": 180.0, "phosphorus": 70.0}'::jsonb,ARRAY['양파와 양배추를 썰어 미지근한 물에 담가 칼륨을 제거합니다.','파인애플을 믹서에 갈아 다진 마늘, 고춧가루와 섞어 무염 양념장을 만듭니다.','돼지고기를 양념장에 재워둡니다.','프라이팬에 고기를 볶다가 전처리한 채소를 넣고 타지 않게 볶아냅니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (14,'recipe-14','무염 소고기 튀김(가라아게)','돈까스','main',ARRAY['저칼륨','저나트륨']::text[],'짠 돈까스 소스와 고칼륨 감자튀김을 배제하고, 소고기를 튀겨내어 식초와 고춧가루 무염 소스로 맛을 냅니다.',ARRAY['소고기 60g','마늘 3g','밀가루 10g','식용유','식초 10g','고춧가루 5g']::text[],'{"kcal": 210.0, "protein": 13.0, "sodium": 60.0, "potassium": 170.0, "phosphorus": 80.0}'::jsonb,ARRAY['소고기를 먹기 좋게 썰고 다진 마늘과 섞어줍니다.','물과 밀가루로 튀김옷을 입혀 뭉친 뒤 기름에 튀겨냅니다.','냄비에 물, 식초, 고춧가루, 소량의 설탕을 끓여 매콤새콤한 소스를 만듭니다.','바삭하게 튀긴 소고기에 무염 소스를 곁들여 냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (15,'recipe-15','과일소스 닭탕수','탕수육','main',ARRAY['저나트륨','저칼륨']::text[],'시판 탕수소스 대신 생사과와 파인애플, 레몬즙의 천연 새콤달콤한 과일즙 베이스로 소금을 완벽히 대체합니다.',ARRAY['닭다리살 60g','사과 20g','파인애플 15g','전분 20g','설탕 5g','레몬즙 10g','저염간장 2g']::text[],'{"kcal": 220.0, "protein": 12.0, "sodium": 80.0, "potassium": 180.0, "phosphorus": 90.0}'::jsonb,ARRAY['닭다리살을 썰어 청주와 후추로만 밑간을 해둡니다 (소금 생략).','사과와 파인애플을 한입 크기로 썰어 준비합니다.','닭에 전분 옷을 입혀 기름에서 바삭하게 튀겨냅니다.','냄비에 저염간장, 설탕, 레몬즙을 끓이다 과일과 전분물을 넣고 튀긴 닭과 버무립니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (16,'recipe-16','레몬 마늘 닭다리살 구이','치킨','main',ARRAY['저나트륨','저칼륨']::text[],'염지된 시판 배달 치킨 대신, 신선한 닭고기를 레몬즙, 마늘, 식초로 절여 구워내어 짠맛 없이 새콤함으로 비린내를 덮습니다.',ARRAY['닭다리살 80g','다진 마늘 5g','식초 5g','레몬즙 5g','전분 5g','식용유']::text[],'{"kcal": 180.0, "protein": 14.0, "sodium": 70.0, "potassium": 160.0, "phosphorus": 100.0}'::jsonb,ARRAY['닭다리살을 깨끗이 씻어 전분을 얇게 입힙니다.','팬에 기름을 두르고 닭다리살 껍질이 바삭해지도록 굽습니다.','다진 마늘을 볶다가 물, 식초, 레몬즙을 넣어 끓여 무염 과일소스를 만듭니다.','접시에 구운 닭을 올리고 레몬마늘 소스를 살짝 뿌려냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (17,'recipe-17','유자소스 삼치구이','생선구이','main',ARRAY['저나트륨']::text[],'생선에 소금 간을 하지 않고 유자청의 상큼함과 달콤함으로 비린내를 잡고 간을 대신합니다.',ARRAY['삼치 50g','유자청 10g','식초 3g','참기름 2g','다진 파/마늘 약간','식용유']::text[],'{"kcal": 140.0, "protein": 10.0, "sodium": 60.0, "potassium": 150.0, "phosphorus": 90.0}'::jsonb,ARRAY['삼치살을 분리해 물기를 닦고 비린내 제거를 위해 레몬즙만 살짝 뿌립니다.','유자청, 식초, 참기름, 파, 마늘을 섞어 무염 소스를 만듭니다.','팬에 식용유를 두르고 삼치를 굽습니다.','거의 익었을 때 유자소스를 덧발라가며 구워 향을 입힙니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (18,'recipe-18','배즙 퓨전 떡갈비','떡갈비','main',ARRAY['저나트륨']::text[],'짠 양념을 줄이고 강판에 간 배즙의 강한 단맛과 다진 마늘, 생강을 이용해 소금 없이 감칠맛을 냅니다.',ARRAY['소고기 다짐육 40g','양파 15g','배 15g','마늘 3g','찹쌀가루 5g','저염간장 3g']::text[],'{"kcal": 160.0, "protein": 9.0, "sodium": 150.0, "potassium": 180.0, "phosphorus": 80.0}'::jsonb,ARRAY['양파는 물에 담가 칼륨을 뺀 후 다지고, 배는 강판에 갈아 즙을 냅니다.','다진 고기에 배즙, 마늘, 저염간장, 찹쌀가루를 넣고 치댑니다.','반죽을 둥글넓적하게 빚어 가운데를 살짝 눌러 줍니다.','기름 두른 팬에 앞뒤로 노릇하게 굽고 약불에서 푹 익혀냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (19,'recipe-19','들깨 소고기 무찜','갈비찜/고기찜','main',ARRAY['저칼륨','저나트륨']::text[],'밤, 대추 등 고칼륨 식재료를 빼고 전처리한 무를 사용하며, 짠 간장 대신 들깨가루로 고소함을 더합니다.',ARRAY['찜용 소고기 50g','무 30g','대파 5g','마늘 3g','들깨가루 10g','저염간장 3g','물 100g']::text[],'{"kcal": 180.0, "protein": 12.0, "sodium": 140.0, "potassium": 170.0, "phosphorus": 90.0}'::jsonb,ARRAY['무는 한입 크기로 썰어 끓는 물에 데친 뒤 물을 버려 칼륨을 제거합니다.','소고기는 핏물을 빼고 겉면을 살짝 데쳐냅니다.','냄비에 소고기, 데친 무, 마늘, 저염간장, 물을 넣고 뭉근하게 끓입니다.','고기가 부드러워지면 들깨가루를 듬뿍 풀어 고소하게 국물을 졸여냅니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (20,'recipe-20','두부 해물 완자','동그랑땡','main',ARRAY['저인','저나트륨']::text[],'고인산 햄이나 가공육을 피하고 오징어와 두부를 활용하며, 소금 대신 천연 새우가루로 감칠맛을 맞춥니다.',ARRAY['두부 30g','오징어 20g','양파 10g','감자전분 10g','새우가루 3g','꿀 3g','식용유']::text[],'{"kcal": 120.0, "protein": 7.0, "sodium": 160.0, "potassium": 130.0, "phosphorus": 70.0}'::jsonb,ARRAY['두부는 으깨어 면보로 수분을 꽉 짜내고 오징어는 잘게 다집니다.','양파는 다져서 물에 2시간 담가 칼륨을 뺍니다.','두부, 해물, 양파, 새우가루, 전분을 섞어 치대어 모양을 잡습니다.','팬에 기름을 두르고 앞뒤로 노릇하게 구워냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (21,'recipe-21','무염 돈수육과 겨자소스','보쌈/수육','main',ARRAY['저나트륨','저칼륨']::text[],'고염 쌈장이나 새우젓 대신 톡 쏘는 겨자가루와 식초 소스를 곁들입니다. 채소는 물에 오래 담가 칼륨을 뺍니다.',ARRAY['돼지고기(수육용) 80g','양파 10g','오이 10g','대파/마늘 약간','겨자가루 5g','식초 5g','설탕 5g']::text[],'{"kcal": 210.0, "protein": 17.0, "sodium": 80.0, "potassium": 190.0, "phosphorus": 110.0}'::jsonb,ARRAY['냄비에 파, 마늘만 듬뿍 넣고 돼지고기를 40분간 푹 삶습니다.','곁들일 양파와 오이는 가늘게 채 썰어 미지근한 물에 2시간 담가 칼륨을 뺍니다.','겨자가루를 따뜻한 물에 개어 발효시킨 뒤 식초, 설탕을 섞어 무염 소스를 만듭니다.','얇게 썬 수육에 전처리한 채소와 겨자소스를 곁들여 냅니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (22,'recipe-22','카레 닭고기 볶음밥','볶음밥','main',ARRAY['저칼륨','저나트륨']::text[],'고칼륨인 토마토 대신 물에 담근 양파와 당근을 사용하고, 짠 소스 대신 소량의 카레가루로 풍미를 대체합니다.',ARRAY['쌀밥 100g','닭가슴살 30g','양파 15g','당근 10g','카레가루 5g','식용유']::text[],'{"kcal": 250.0, "protein": 12.0, "sodium": 180.0, "potassium": 140.0, "phosphorus": 80.0}'::jsonb,ARRAY['당근과 양파는 잘게 다져 미지근한 물에 2시간 담가 칼륨을 뺍니다.','닭가슴살은 잘게 썰어 준비합니다.','팬에 기름을 두르고 닭가슴살과 전처리한 채소를 볶습니다.','채소가 익으면 밥과 카레가루를 넣고 고루 섞어 볶아냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (23,'recipe-23','전처리 채소 비빔밥','비빔밥','main',ARRAY['저칼륨','저나트륨']::text[],'고칼륨 시금치, 버섯을 철저히 빼고, 당근, 양파, 무를 모두 데쳐 칼륨을 제거합니다. 고추장 대신 매실청 소스를 씁니다.',ARRAY['쌀밥 100g','무 20g','당근 15g','양파 15g','소고기 20g','매실청 5g','식초 3g','참기름 2g']::text[],'{"kcal": 260.0, "protein": 9.0, "sodium": 90.0, "potassium": 180.0, "phosphorus": 70.0}'::jsonb,ARRAY['무, 당근, 양파를 가늘게 채 썰어 끓는 물에 푹 데친 후 물기를 꽉 짭니다.','소고기는 기름 없이 마른 팬에 바싹 볶습니다.','매실청, 식초, 소량의 고춧가루, 참기름을 섞어 무염 비빔장을 만듭니다.','그릇에 밥, 전처리한 채소, 소고기를 올리고 소스에 비벼 먹습니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (24,'recipe-24','레몬즙 오징어 볶음','오징어볶음','main',ARRAY['저나트륨','저칼륨']::text[],'짠 고추장 양념 대신 레몬즙의 강한 산미와 향신채(마늘), 소량의 고춧가루로 매콤함을 내어 간을 대체합니다.',ARRAY['오징어 50g','양파 20g','마늘 3g','레몬즙 5g','고춧가루 2g','식용유']::text[],'{"kcal": 120.0, "protein": 9.0, "sodium": 150.0, "potassium": 170.0, "phosphorus": 90.0}'::jsonb,ARRAY['양파를 썰어 물에 2시간 이상 담가 칼륨을 뺍니다.','오징어는 안쪽에 칼집을 넣어 한입 크기로 썹니다.','가열된 팬에 기름을 두르고 다진 마늘, 전처리한 양파, 오징어를 차례로 볶습니다.','다 익었을 때 고춧가루와 레몬즙을 뿌리고 가볍게 버무려 완성합니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (25,'recipe-25','삼치 무염 장조림','장조림','main',ARRAY['저나트륨']::text[],'고기를 짠 간장에 푹 끓이는 대신, 생선을 구운 후 소량의 물엿과 마늘 코팅만으로 짭짤한 느낌을 대체합니다.',ARRAY['삼치 50g','전분 5g','다진 마늘 3g','물엿 5g','식용유']::text[],'{"kcal": 150.0, "protein": 10.0, "sodium": 60.0, "potassium": 160.0, "phosphorus": 100.0}'::jsonb,ARRAY['삼치는 후추로 비린내를 잡고 소금은 절대 치지 않습니다.','삼치 겉면에 전분을 얇게 골고루 묻힙니다.','달군 팬에 식용유를 두르고 삼치를 앞뒤로 노릇하게 굽습니다.','팬 구석에 다진 마늘, 물엿, 소량의 물을 끓이다 구운 삼치에 자작하게 졸여 코팅합니다.']::text[],'https://images.unsplash.com/photo-1512058564366-18510be2db19?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (26,'recipe-26','쌀국수 해산물 볶음면','잔치국수','main',ARRAY['저나트륨','저인']::text[],'소금/인이 함유된 밀가루 소면 대신 쌀국수를 사용하고, 국물 섭취로 인한 나트륨 축적을 막고자 볶음면으로 만듭니다.',ARRAY['쌀국수 50g','새우 20g','양파 15g','다진 마늘 3g','식초 5g','고춧가루 2g','식용유']::text[],'{"kcal": 230.0, "protein": 6.0, "sodium": 140.0, "potassium": 130.0, "phosphorus": 60.0}'::jsonb,ARRAY['쌀국수는 찬물에 30분 이상 불렸다가 끓는 물에 데쳐냅니다.','양파는 채 썰어 물에 담가 칼륨을 제거합니다.','팬에 식용유를 두르고 마늘, 전처리한 양파, 새우를 볶습니다.','새우가 익으면 데친 쌀국수를 넣고 식초와 고춧가루만 섞어 매콤새콤하게 볶아냅니다.']::text[],'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (27,'recipe-27','무염 사과즙 겉절이','배추김치/겉절이','side',ARRAY['저나트륨','저칼륨']::text[],'배추를 소금에 절이는 방식을 완벽히 버리고, 물에 담가 고칼륨을 뺀 후 사과 즙과 식초로 나트륨을 배제합니다.',ARRAY['알배추 40g','양파 10g','사과 15g','고춧가루 3g','식초 5g','매실액 2g']::text[],'{"kcal": 35.0, "protein": 1.0, "sodium": 10.0, "potassium": 140.0, "phosphorus": 20.0}'::jsonb,ARRAY['알배추와 양파를 썰어 미지근한 물에 2시간 이상 담가 칼륨을 확실히 제거합니다.','사과를 강판에 곱게 갈아 즙을 냅니다.','사과즙에 다진 마늘(소량), 고춧가루, 매실액, 식초를 섞어 무염 양념을 만듭니다.','물기를 뺀 배추와 양파를 양념장에 버무려 신선하게 섭취합니다.']::text[],'https://images.unsplash.com/photo-1467453678174-768ec283a940?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (28,'recipe-28','콜라비 무염 깍두기','깍두기/무생채','side',ARRAY['저나트륨','저칼륨']::text[],'단맛과 아삭함이 매우 강한 콜라비를 사용하여 소금 절임을 완벽히 생략합니다. 잘게 썰어 물에 담가 칼륨을 뺍니다.',ARRAY['콜라비 60g','고춧가루 3g','매실청 2g','다진 마늘 소량']::text[],'{"kcal": 25.0, "protein": 1.0, "sodium": 15.0, "potassium": 130.0, "phosphorus": 20.0}'::jsonb,ARRAY['콜라비의 껍질을 벗기고 깍둑 썰어 미지근한 물에 2시간 담가 칼륨을 제거합니다.','믹서에 마늘 소량을 곱게 갑니다.','간 마늘에 고춧가루, 매실청을 섞어 무염 양념을 완성합니다.','물기를 제거한 콜라비에 양념을 붓고 버무린 후 실온에서 하루 숙성시킵니다.']::text[],'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (29,'recipe-29','씻은 김치 양배추 볶음','김치볶음','side',ARRAY['저나트륨','저칼륨']::text[],'짠 김치는 물에 깨끗이 씻어내어 고칼륨 양념과 나트륨을 날리고, 보리새우의 감칠맛으로 짠맛을 대신합니다.',ARRAY['씻은 배추김치 30g','양배추 30g','마른 보리새우 2g','들기름 3g']::text[],'{"kcal": 45.0, "protein": 2.0, "sodium": 180.0, "potassium": 120.0, "phosphorus": 35.0}'::jsonb,ARRAY['배추김치는 물에 여러 번 헹궈 고춧가루와 짠맛을 완벽히 씻어내고 썹니다.','양배추는 채 썰어 미지근한 물에 2시간 담가 칼륨을 제거한 후 건집니다.','마른 팬에 보리새우를 살짝 볶은 후 절구에 곱게 갑니다.','팬에 들기름을 두르고 씻은 김치와 양배추를 볶다가 숨이 죽으면 새우가루를 뿌려 완성합니다.']::text[],'https://images.unsplash.com/photo-1467453678174-768ec283a940?w=640&h=360&fit=crop');
insert into public.recipes (recipe_no,slug,name,original_dish,category,substitute_tags,substitute_point,ingredients,nutrients,steps,image_url) values (30,'recipe-30','파 채소 달걀말이','계란말이','side',ARRAY['저나트륨','저칼륨']::text[],'소금을 치지 않고 데친 양파와 다진 파(물에 담가 칼륨 제거)의 단맛과 후추만으로 맛을 내며 계란으로 양질의 단백질을 채웁니다.',ARRAY['*   **저인 (고인 식재료 🚫):** **유제품(우유','치즈)','견과류','잡곡','가공육(햄','소시지)**은 체내 인 축적을 유발하므로 철저히 피하고','흰쌀밥과 신선한 살코기 위주로 섭취합니다.']::text[],'{"kcal": 100.0, "protein": 6.0, "sodium": 70.0, "potassium": 110.0, "phosphorus": 90.0}'::jsonb,ARRAY['양파와 대파를 곱게 다져 미지근한 물에 2시간 이상 담가 고칼륨을 뺍니다.','전처리한 채소의 물기를 꽉 짠 뒤, 계란을 풀고 후추와 채소를 섞습니다 (소금 금지).','팬에 식용유를 두르고 계란물을 부어 약불에서 서서히 익힙니다.','조심스럽게 돌돌 말아 식힌 후 한입 크기로 썰어 냅니다.']::text[],'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=640&h=360&fit=crop');
