-- 레시피 코치 콘텐츠 (KidneyDiseaseFoodRecipes.txt 30선) — Supabase SQL Editor에서 1회 실행
create table if not exists public.recipes (
  id uuid primary key default gen_random_uuid(),
  recipe_no int, slug text unique, name text not null, original_dish text,
  category text, substitute_tags text[], substitute_point text,
  ingredients text[], nutrients jsonb, steps text[], image_url text,
  created_at timestamptz default now());
alter table public.recipes enable row level security;
drop policy if exists recipes_select on public.recipes;
create policy recipes_select on public.recipes for select using (true);
delete from public.recipes;
